// CommunityToolkit.HighPerformance StringPool
// Install: dotnet add package CommunityToolkit.HighPerformance

using CommunityToolkit.HighPerformance.Buffers;

// Parse JSON field name — intern để dedup
string GetFieldName(ReadOnlySpan<char> rawSpan)
    => StringPool.Shared.GetOrAdd(rawSpan);

// Span-based parsing — zero alloc
void ParseLine(ReadOnlySpan<char> line)
{
    int colonIdx = line.IndexOf(':');
    ReadOnlySpan<char> key = line[..colonIdx].Trim();
    ReadOnlySpan<char> value = line[(colonIdx + 1)..].Trim();

    // Chỉ convert sang string nếu thực sự cần lưu
    if (key.Equals("Content-Type", StringComparison.OrdinalIgnoreCase))
        _contentType = value.ToString(); // 1 alloc
    // Không allocate nếu chỉ đọc
}

// string.Create() cho concatenation tối ưu
string FormatId(int tenantId, int userId) =>
    string.Create(20, (tenantId, userId),
        (span, state) =>
        {
            state.tenantId.TryFormat(span, out int n);
            span[n] = ':';
            state.userId.TryFormat(span[(n+1)..], out _);
        });
